13	@ccclass( "EnterRespinState" )
14	export class EnterRespinState extends BaseState
15	{
16	    private m_gameView: GameView = null;
17	
18	    /**@ch 首手進場等待時間（秒） */
19	    private static readonly WAIT_TIME = 0.8;
20	
21	    /**@ch 宣告動畫開關（預留接縫）：預設不播；連首手都不播。
22	     * 未來若要恢復「首手播 Respin 宣告動畫」，改為 true 即可（續轉手一律不播）。 */
23	    private static readonly PLAY_ENTER_ANIM: boolean = false;
24	
25	    /**@ch col 0/5 靜態張排除開關：true=重建靜態圖時跳過 col 0/5（RespinLockColumns）。
26	     * 這兩列已由 SetColumnLock 整輪鎖定（reel 不轉、原符號自然留存），毋須 EffectPlate 再疊靜態張。
27	     * server 改為 RespinLockedPos 含 col 0/5 後集合會帶這兩列 entry，故以此開關控制是否略過顯示處理。
28	     * 設 false 則回復「對集合內所有 entry（含 col 0/5）都疊靜態張」的舊行為。 */
29	    private static readonly EXCLUDE_LOCK_COLUMNS_FROM_STATIC: boolean = true;
30	
31	    constructor( gameView: GameView )
32	    {
33	        super();
34	        this.m_gameView = gameView;
35	    }
36	
37	    public async OnEnter()
38	    {
39	        console.log( "OnEnter State: ENTER_RESPIN" );
40	
41	        // 首手 / 續轉分流：首手時 IsRespinGame 尚未設為 true
42	        const isFirstHand = !this.m_gameView.IsRespinGame;
43	
44	        if ( isFirstHand )
45	        {
46	            // 首手進場：緩衝等待 → 設 Respin 狀態 → 清盤（鎖列在 HandleReel 內處理）
47	            await Define.Wait( this.m_gameView, EnterRespinState.WAIT_TIME );
48	            this.m_gameView.IsRespinGame = true;
49	            this.m_gameView.ClearAll();
50	        }
51	
52	        // 累加本手鎖定位置 + 以累積集合冪等重建靜態圖（首手與續轉同邏輯）
53	        this.HandleReel();
54	
55	        // 宣告動畫：可開關，僅首手且開關開啟時播（預設不播，續轉手一律不播）
56	        if ( isFirstHand && EnterRespinState.PLAY_ENTER_ANIM )
57	        {
58	            await this.PlayRespinEnterAnimation();
59	        }
60	
61	        // 去向改 SPIN（v2 骨架）：plate 內循環繞過 ROUND_END，續轉播下一手 plate；
62	        // 整局 plate 用盡後由 CheckState ② 走 LEAVE_RESPIN → ROUND_END（RoundInfo 級一次）
63	        stateManager.NextState( CommonState.SPIN );
64	    }
65	
66	    public OnProcess()
67	    {
68	
69	    }
70	
71	    public OnLeave()
72	    {
73	
74	    }
